You are implementing a BTreeMap migration for a Rust project. Make the following precise changes to 5 production files. DO NOT run cargo build or tests — just edit the files. Report what you changed.

Working directory: /Users/bhyslop/projects/rbm_alpha_recipemuster

## File 1: Tools/jjk/vov_veiled/src/jjrt_types.rs

Read the file first, then make these changes:

1. Remove line `use indexmap::IndexMap;` (it's around line 11)
2. In the `jjrg_Gallops` struct (around line 74-78), add `heat_order` field and change `heats` type:
   - CURRENT struct body:
     ```
     pub next_heat_seed: String,
     pub heats: IndexMap<String, jjrg_Heat>,
     ```
   - NEW struct body:
     ```
     pub next_heat_seed: String,
     #[serde(default, skip_serializing_if = "Vec::is_empty")]
     pub heat_order: Vec<String>,
     pub heats: BTreeMap<String, jjrg_Heat>,
     ```
   Note: `BTreeMap` is already imported via `use std::collections::BTreeMap;` at line 10.

## File 2: Tools/jjk/vov_veiled/src/jjri_io.rs

Read the file first. In `jjdr_load` function, make these changes:

**Change 1:** After deserializing `gallops` (after `let mut gallops: jjrg_Gallops = serde_json::from_slice...`), detect migration mode:
```rust
// Detect old-format files: heat_order absent in JSON → serde default → empty vec.
// Old-format files cannot pass round-trip check because BTreeMap serializes heats
// in sorted key order, which differs from original furlough-shuffled order.
let is_migration_mode = gallops.heat_order.is_empty();
```

**Change 2:** Wrap the entire round-trip validation block in `if !is_migration_mode { ... }`:
Current code (approximately lines 95-102):
```rust
// Round-trip validation: run before recomputation to validate the stored format
let reserialized = serde_json::to_string_pretty(&gallops)
    .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;

if reserialized.as_bytes() != original_bytes {
    let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
    return Err(format!("Round-trip validation failed at byte {}", diff_pos));
}
```
Wrap it so it becomes:
```rust
// Round-trip validation: run before recomputation to validate the stored format.
// Skipped for old-format files (heat_order empty) — BTreeMap key order differs from
// original IndexMap insertion order, so round-trip will always fail for these files.
if !is_migration_mode {
    let reserialized = serde_json::to_string_pretty(&gallops)
        .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;

    if reserialized.as_bytes() != original_bytes {
        let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
        return Err(format!("Round-trip validation failed at byte {}", diff_pos));
    }
}
```

**Change 3:** After the paddock_file recomputation loop (around line 111, after the loop that sets `heat.paddock_file = jjri_paddock_path(bare);`), add heat_order population:
```rust
// Populate heat_order from sorted heats keys on first load of old-format file.
// BTreeMap guarantees sorted key order here.
if is_migration_mode {
    gallops.heat_order = gallops.heats.keys().cloned().collect();
}
```

## File 3: Tools/jjk/vov_veiled/src/jjro_ops.rs

Read the file first, then make these changes:

**Change 1 — Nominate:** After `gallops.heats.insert(firemark_str.clone(), heat);` (around line 68), add:
```rust
gallops.heat_order.push(firemark_str.clone());
```

**Change 2 — Retire:** Find this code (around line 557-559):
```rust
    // Remove heat from gallops (do NOT change next_heat_seed)
    // Use shift_remove to preserve order of remaining heats
    gallops.heats.shift_remove(&firemark_key);
```
Replace with:
```rust
    // Remove heat from gallops (do NOT change next_heat_seed)
    gallops.heats.remove(&firemark_key);
    gallops.heat_order.retain(|f| f != &firemark_key);
```

**Change 3 — Furlough:** Find the furlough status-change block (around lines 797-812). It currently has code like:
```rust
    // Note: requesting the same status is allowed — it promotes the heat
    // to the top of its list (racing or stabled) for reordering purposes.
    }

    // Apply status change if requested — also promotes heat to top of list
    if args.racing {
        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
        }
    } else if args.stabled {
        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
        }
    }
```
Replace with (removing the comment about promoting to top, removing shift_remove/shift_insert, keeping only status assignment):
```rust
        // Note: requesting the same status is allowed (idempotent).
    }

    // Apply status change if requested — status only, no reordering
    if args.racing {
        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
    } else if args.stabled {
        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
    }
```

**Change 4 — Garland:** Find this code (around lines 954-960):
```rust
    // Set new heat status to racing and move to front
    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
    new_heat_mut.status = jjrg_HeatStatus::Racing;
    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
    }
```
Replace with:
```rust
    // Set new heat status to racing and move to front of heat_order
    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
    new_heat_mut.status = jjrg_HeatStatus::Racing;
    gallops.heat_order.retain(|f| f != &new_firemark_key);
    gallops.heat_order.insert(0, new_firemark_key.clone());
```

After all garland changes, verify there are no remaining `shift_remove` or `shift_insert` calls in jjro_ops.rs. Remove them if any remain (there should not be any after these changes).

## File 4: Tools/jjk/vov_veiled/src/jjrmu_muster.rs

Read the file first. The current code (around line 37) does:
```rust
let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
```
followed by a status-based sort.

Replace the collection + sort with heat_order-based iteration. The new approach:
- Iterate `gallops.heat_order` to get display order
- For each firemark in heat_order, look up the heat in `gallops.heats`
- Apply status filter if specified
- Display in heat_order order (NO sort by status — heat_order IS the display order)

Specifically, replace this section:
```rust
    // Collect heats with status info for sorting
    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();

    // Apply status filter if specified
    if let Some(ref filter_status) = args.status {
        let filter_lowercase = filter_status.to_lowercase();
        heats_by_status.retain(|(_, heat)| {
            let heat_status_str = match heat.status {
                HeatStatus::Racing => "racing",
                HeatStatus::Stabled => "stabled",
                HeatStatus::Retired => "retired",
            };
            heat_status_str == filter_lowercase
        });
    }

    // Sort: racing first, then stabled, then retired
    heats_by_status.sort_by(|a, b| {
        let a_status_order = match a.1.status {
            HeatStatus::Racing => 0,
            HeatStatus::Stabled => 1,
            HeatStatus::Retired => 2,
        };
        let b_status_order = match b.1.status {
            HeatStatus::Racing => 0,
            HeatStatus::Stabled => 1,
            HeatStatus::Retired => 2,
        };
        a_status_order.cmp(&b_status_order)
    });
```

With:
```rust
    // Collect heats in heat_order sequence (explicit user-defined priority order)
    let ordered_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
        .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
        .collect();

    // Apply status filter if specified
    let heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = if let Some(ref filter_status) = args.status {
        let filter_lowercase = filter_status.to_lowercase();
        ordered_heats.into_iter().filter(|(_, heat)| {
            let heat_status_str = match heat.status {
                HeatStatus::Racing => "racing",
                HeatStatus::Stabled => "stabled",
                HeatStatus::Retired => "retired",
            };
            heat_status_str == filter_lowercase
        }).collect()
    } else {
        ordered_heats
    };
```

Note: the rest of the function uses `heats_by_status` as the iteration variable, so the downstream code (measure loop and print loop) should work unchanged.

## File 5: Tools/jjk/vov_veiled/src/jjrq_query.rs

Read the file first. Find `jjrq_resolve_default_heat` (around line 27-34):
```rust
pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    for (heat_key, heat) in &gallops.heats {
        if heat.status == HeatStatus::Racing {
            return Ok(heat_key.clone());
        }
    }
    Err("No racing heats found".to_string())
}
```
Replace with:
```rust
pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    for heat_key in &gallops.heat_order {
        if let Some(heat) = gallops.heats.get(heat_key) {
            if heat.status == HeatStatus::Racing {
                return Ok(heat_key.clone());
            }
        }
    }
    Err("No racing heats found".to_string())
}
```

