     4→
     5→//! Gallops I/O operations with validation
     6→//!
     7→//! Provides validated load/save operations for Gallops JSON with round-trip guarantees.
     8→
     9→use std::fs;
    10→use std::path::Path;
    11→use crate::jjrt_types::jjrg_Gallops;
    12→use crate::jjrv_validate::jjrg_validate;
    13→
    14→/// Validated Gallops wrapper
    15→///
    16→/// This newtype ensures that Gallops instances are validated on load.
    17→/// Only jjdr_load can create instances, guaranteeing all ValidatedGallops
    18→/// have passed both deserialization and semantic validation.
    19→pub struct jjdr_ValidatedGallops(jjrg_Gallops);
    20→
    21→impl jjdr_ValidatedGallops {
    22→    /// Access the inner Gallops (immutable)
    23→    pub fn inner(&self) -> &jjrg_Gallops {
    24→        &self.0
    25→    }
    26→
    27→    /// Access the inner Gallops (mutable)
    28→    pub fn inner_mut(&mut self) -> &mut jjrg_Gallops {
    29→        &mut self.0
    30→    }
    31→
    32→    /// Consume the wrapper and return the inner Gallops
    33→    pub fn into_inner(self) -> jjrg_Gallops {
    34→        self.0
    35→    }
    36→
    37→    /// Test-only constructor (bypasses validation)
    38→    #[cfg(test)]
    39→    pub fn test_wrap(g: jjrg_Gallops) -> Self {
    40→        Self(g)
    41→    }
    42→}
    43→
    44→/// Find first byte position where two byte slices differ
    45→fn zjjdr_find_first_diff(a: &[u8], b: &[u8]) -> usize {
    46→    a.iter()
    47→        .zip(b.iter())
    48→        .position(|(x, y)| x != y)
    49→        .unwrap_or_else(|| a.len().min(b.len()))
    50→}
    51→
    52→/// Encode a firemark string into a case-safe paddock filename path.
    53→///
    54→/// Each character is prefixed with 'u' (uppercase) or 'l' (lowercase),
    55→/// ensuring the resulting filename is unambiguous on case-insensitive
    56→/// filesystems (macOS HFS+/APFS).
    57→///
    58→/// Examples:
    59→///   "AG" → ".claude/jjm/jjp_uAuG.md"
    60→///   "Ag" → ".claude/jjm/jjp_uAlg.md"
    61→///   "ag" → ".claude/jjm/jjp_lalg.md"
    62→pub fn jjri_paddock_path(firemark: &str) -> String {
    63→    let encoded: String = firemark.chars().map(|c| {
    64→        if c.is_uppercase() {
    65→            format!("u{}", c)
    66→        } else {
    67→            format!("l{}", c)
    68→        }
    69→    }).collect();
    70→    format!(".claude/jjm/jjp_{}.md", encoded)
    71→}
    72→
    73→/// Load and validate Gallops from a file
    74→///
    75→/// Performs these steps in order:
    76→/// 1. Deserialize JSON to Gallops struct
    77→/// 2. Round-trip validation: reserialize and compare bytes (validates stored format)
    78→/// 3. Recompute paddock_file from firemark for every heat (JJK owns this field)
    79→/// 4. Paddock existence check: fatal with mv instructions if files are at legacy paths
    80→/// 5. Semantic validation via jjrg_validate
    81→///
    82→/// Step 3 means the stored paddock_file value is ignored — JJK always derives it from
    83→/// the firemark. After migration, the next save writes the encoded value back to disk.
    84→///
    85→/// Returns ValidatedGallops wrapper that guarantees the data has passed all checks.
    86→pub fn jjdr_load(path: &Path) -> Result<jjdr_ValidatedGallops, String> {
    87→    // Read original bytes
    88→    let original_bytes = fs::read(path)
    89→        .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
    90→
    91→    // Deserialize (mut: paddock_file will be recomputed below)
    92→    let mut gallops: jjrg_Gallops = serde_json::from_slice(&original_bytes)
    93→        .map_err(|e| format!("Failed to parse JSON: {}", e))?;
    94→
    95→    // Round-trip validation: run before recomputation to validate the stored format
    96→    let reserialized = serde_json::to_string_pretty(&gallops)
    97→        .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;
    98→
    99→    if reserialized.as_bytes() != original_bytes {
   100→        let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
   101→        return Err(format!("Round-trip validation failed at byte {}", diff_pos));
   102→    }
   103→
   104→    // Recompute paddock_file from firemark for every heat.
   105→    // JJK owns this field exclusively; whatever is stored in JSON is overwritten.
   106→    // This allows old gallops files (with raw-firemark paths) to load transparently —
   107→    // the correct encoded path is used in memory, and written back on the next save.
   108→    for (firemark_key, heat) in &mut gallops.heats {
   109→        let bare = firemark_key.trim_start_matches('₣');
   110→        heat.paddock_file = jjri_paddock_path(bare);
   111→    }
   112→
   113→    // Paddock existence check: verify each encoded paddock file exists on disk.
   114→    // If missing, compute the legacy raw-firemark path and emit mv instructions.
   115→    // Reports ALL missing files at once so a single repair pass suffices.
   116→    {
   117→        let mut repairs: Vec<String> = Vec::new();
   118→        for (firemark_key, heat) in &gallops.heats {
   119→            if !Path::new(&heat.paddock_file).exists() {
   120→                let bare = firemark_key.trim_start_matches('₣');
   121→                let legacy_path = format!(".claude/jjm/jjp_{}.md", bare);
   122→                if Path::new(&legacy_path).exists() {
   123→                    repairs.push(format!("  mv {} {}", legacy_path, heat.paddock_file));
   124→                } else {
   125→                    repairs.push(format!(
   126→                        "  # WARNING: paddock missing for heat \"{}\", expected: {}",
   127→                        bare, heat.paddock_file
   128→                    ));
   129→                }
   130→            }
   131→        }
   132→        if !repairs.is_empty() {
   133→            return Err(format!(
   134→                "Paddock files need renaming before proceeding:\n\n{}",
   135→                repairs.join("\n")
   136→            ));
   137→        }
   138→    }
   139→
   140→    // Semantic validation
   141→    jjrg_validate(&gallops)
   142→        .map_err(|errors| format!("Validation failed: {}", errors.join("; ")))?;
   143→
   144→    Ok(jjdr_ValidatedGallops(gallops))
   145→}
   146→
   147→/// Save Gallops to a file with validation
   148→///
   149→/// Performs atomic write with validation:
   150→/// 1. Serialize to JSON
   151→/// 2. Write to temp file
   152→/// 3. Validate temp file via jjdr_load
   153→/// 4. Rename temp to target (atomic)
   154→///
   155→/// If validation fails, temp file is deleted and error returned.
   156→pub fn jjdr_save(gallops: &jjrg_Gallops, path: &Path) -> Result<(), String> {
   157→    // Serialize to pretty JSON
   158→    let json = serde_json::to_string_pretty(gallops)
   159→        .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   160→
   161→    // Create temp file in same directory for atomic rename
   162→    let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   163→    let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   164→
   165→    // Write to temp file
   166→    fs::write(&temp_path, &json)
   167→        .map_err(|e| format!("Failed to write temp file: {}", e))?;
   168→
   169→    // Validate what we wrote by loading it back
   170→    match jjdr_load(&temp_path) {
   171→        Ok(_) => {
   172→            // Validation passed, rename to target
   173→            fs::rename(&temp_path, path)
   174→                .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   175→            Ok(())
   176→        }
   177→        Err(e) => {
   178→            // Validation failed, clean up temp file
   179→            let _ = fs::remove_file(&temp_path);
   180→            Err(format!("Save validation failed: {}", e))
   181→        }
   182→    }
   183→}
   184→
   185→/// Save Gallops and commit with paddock in a single operation
   186→///
   187→/// This is the standard routine for JJK operations that modify gallops.
   188→/// It saves the gallops file, then commits both the gallops and the paddock file
   189→/// for the given heat using machine_commit.
   190→///
   191→/// Returns the commit hash on success.
   192→pub fn jjri_persist(
   193→    lock: &vvc::vvcc_CommitLock,
   194→    gallops: &jjrg_Gallops,
   195→    file: &Path,
   196→    firemark: &crate::jjrf_favor::jjrf_Firemark,
   197→    message: String,
   198→    size_limit: u64,
   199→) -> Result<String, String> {
   200→    // Save gallops first
   201→    jjdr_save(gallops, file)?;
   202→
   203→    // Construct paths for commit
   204→    let gallops_path = file.to_string_lossy().to_string();
   205→    let paddock_path = jjri_paddock_path(firemark.jjrf_as_str());
   206→
   207→    // Commit using machine_commit with explicit file list
   208→    let commit_args = vvc::vvcm_CommitArgs {
   209→        files: vec![
   210→            gallops_path,
   211→            paddock_path,
   212→        ],
   213→        message,
   214→        size_limit,
   215→        warn_limit: 30000,
   216→    };
   217→
   218→    vvc::machine_commit(lock, &commit_args)
   219→}
   220→

