    20→/// Nominate a new Heat
    21→///
    22→/// Creates a new Heat with empty Pace structure and creates the paddock file.
    23→pub fn jjrg_nominate(gallops: &mut jjrg_Gallops, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
    24→    // Validate silks is alphanumeric-kebab
    25→    if !zjjrg_is_kebab_case(&args.silks) {
    26→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
    27→    }
    28→
    29→    // Validate created is YYMMDD
    30→    if !zjjrg_is_yymmdd(&args.created) {
    31→        return Err(format!("created must be YYMMDD format, got '{}'", args.created));
    32→    }
    33→
    34→    // Allocate Firemark from next_heat_seed
    35→    let firemark_str = format!("{}{}", FIREMARK_PREFIX, gallops.next_heat_seed);
    36→    let heat_id = gallops.next_heat_seed.clone();
    37→
    38→    // Compute paddock path
    39→    let paddock_file = jjri_paddock_path(&heat_id);
    40→
    41→    // Create paddock file with template
    42→    let paddock_path = base_path.join(&paddock_file);
    43→    if let Some(parent) = paddock_path.parent() {
    44→        fs::create_dir_all(parent)
    45→            .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
    46→    }
    47→
    48→    let paddock_content = format!(
    49→        "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
    50→        args.silks
    51→    );
    52→
    53→    fs::write(&paddock_path, paddock_content)
    54→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
    55→
    56→    // Create new Heat
    57→    let heat = jjrg_Heat {
    58→        silks: args.silks,
    59→        creation_time: args.created,
    60→        status: jjrg_HeatStatus::Stabled,
    61→        order: Vec::new(),
    62→        next_pace_seed: "AAA".to_string(),
    63→        paddock_file,
    64→        paces: BTreeMap::new(),
    65→    };
    66→
    67→    // Insert Heat
    68→    gallops.heats.insert(firemark_str.clone(), heat);
    69→
    70→    // Increment next_heat_seed
    71→    gallops.next_heat_seed = zjjrg_increment_seed(&gallops.next_heat_seed);
    72→
    73→    Ok(jjrg_NominateResult { firemark: firemark_str })
    74→}
