    76→/// Slate a new Pace
    77→///
    78→/// Adds a new Pace to a Heat with an initial Tack in rough state.
    79→/// Positioning: use before/after/first to insert at specific location.
    80→pub fn jjrg_slate(gallops: &mut jjrg_Gallops, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
    81→    // Validate silks is alphanumeric-kebab
    82→    if !zjjrg_is_kebab_case(&args.silks) {
    83→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
    84→    }
    85→
    86→    // Validate text is non-empty
    87→    if args.text.is_empty() {
    88→        return Err("text must not be empty".to_string());
    89→    }
    90→
    91→    // Validate positioning mutual exclusivity
    92→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
    93→        .iter()
    94→        .filter(|&&x| x)
    95→        .count();
    96→    if position_count > 1 {
    97→        return Err("Only one of --before, --after, or --first may be specified".to_string());
    98→    }
    99→
   100→    // Parse and normalize firemark
   101→    let firemark = Firemark::jjrf_parse(&args.firemark)
   102→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   103→    let firemark_key = firemark.jjrf_display();
   104→
   105→    // Verify Heat exists
   106→    let heat = gallops.heats.get_mut(&firemark_key)
   107→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   108→
   109→    // If --before or --after specified, validate target coronet exists
   110→    let insert_position = if let Some(ref before_str) = args.before {
   111→        let target = Coronet::jjrf_parse(before_str)
   112→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   113→        let target_key = target.jjrf_display();
   114→        let pos = heat.order.iter().position(|c| c == &target_key)
   115→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   116→        Some(pos) // Insert before this position
   117→    } else if let Some(ref after_str) = args.after {
   118→        let target = Coronet::jjrf_parse(after_str)
   119→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   120→        let target_key = target.jjrf_display();
   121→        let pos = heat.order.iter().position(|c| c == &target_key)
   122→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   123→        Some(pos + 1) // Insert after this position
   124→    } else if args.first {
   125→        Some(0) // Insert at beginning
   126→    } else {
   127→        None // Append to end (default)
   128→    };
   129→
   130→    // Construct Coronet
   131→    let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   132→
   133→    // Create initial Tack and Pace
   134→    let tack = jjrg_make_tack(
   135→        jjrg_PaceState::Rough,
   136→        args.text,
   137→        args.silks,
   138→        None,
   139→    );
   140→    let pace = jjrg_Pace {
   141→        tacks: vec![tack],
   142→    };
   143→
   144→    // Insert into order at determined position
   145→    match insert_position {
   146→        Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   147→        None => heat.order.push(coronet_str.clone()),
   148→    }
   149→    heat.paces.insert(coronet_str.clone(), pace);
   150→
   151→    // Increment next_pace_seed
   152→    heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   153→
   154→    Ok(jjrg_SlateResult { coronet: coronet_str })
   155→}
