   157→/// Rail - reorder Paces within a Heat
   158→///
   159→/// Supports two modes:
   160→/// - Order mode: replace entire sequence with provided order array
   161→/// - Move mode: relocate a single pace using positioning flags
   162→pub fn jjrg_rail(gallops: &mut jjrg_Gallops, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   163→    // Parse and normalize firemark
   164→    let firemark = Firemark::jjrf_parse(&args.firemark)
   165→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   166→    let firemark_key = firemark.jjrf_display();
   167→
   168→    // Verify Heat exists
   169→    let heat = gallops.heats.get_mut(&firemark_key)
   170→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   171→
   172→    // Mode detection: if move_coronet present, use move mode
   173→    if let Some(ref move_str) = args.move_coronet {
   174→        // Move mode validation
   175→        if !args.order.is_empty() {
   176→            return Err("Cannot combine --move with positional coronets".to_string());
   177→        }
   178→
   179→        // Parse and normalize move coronet
   180→        let move_coronet = Coronet::jjrf_parse(move_str)
   181→            .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   182→        let move_key = move_coronet.jjrf_display();
   183→
   184→        // Validate move coronet exists in heat
   185→        if !heat.paces.contains_key(&move_key) {
   186→            return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   187→        }
   188→
   189→        // Count positioning flags
   190→        let position_count = [
   191→            args.before.is_some(),
   192→            args.after.is_some(),
   193→            args.first,
   194→            args.last,
   195→        ].iter().filter(|&&x| x).count();
   196→
   197→        if position_count == 0 {
   198→            return Err("Move mode requires exactly one positioning flag".to_string());
   199→        }
   200→        if position_count > 1 {
   201→            let mut flags = Vec::new();
   202→            if args.before.is_some() { flags.push("--before"); }
   203→            if args.after.is_some() { flags.push("--after"); }
   204→            if args.first { flags.push("--first"); }
   205→            if args.last { flags.push("--last"); }
   206→            return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   207→        }
   208→
   209→        // Determine target position and validate
   210→        let current_pos = heat.order.iter().position(|c| c == &move_key)
   211→            .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   212→
   213→        let new_pos = if args.first {
   214→            // Find first actionable pace (rough or bridled)
   215→            // If none found, use end of array (nothing actionable to precede)
   216→            let first_actionable_idx = heat.order.iter().position(|coronet| {
   217→                if let Some(pace) = heat.paces.get(coronet) {
   218→                    if let Some(tack) = pace.tacks.first() {
   219→                        matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   220→                    } else {
   221→                        false
   222→                    }
   223→                } else {
   224→                    false
   225→                }
   226→            });
   227→            // Use len() as fallback so adjustment logic works correctly for "end" position
   228→            let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   229→            // If moving from before target, the target shifts down after removal
   230→            if current_pos < target_idx {
   231→                target_idx - 1
   232→            } else {
   233→                target_idx
   234→            }
   235→        } else if args.last {
   236→            heat.order.len() - 1
   237→        } else if let Some(ref before_str) = args.before {
   238→            let target = Coronet::jjrf_parse(before_str)
   239→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   240→            let target_key = target.jjrf_display();
   241→
   242→            if target_key == move_key {
   243→                return Err("Cannot position pace relative to itself".to_string());
   244→            }
   245→
   246→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   247→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   248→
   249→            // If moving from before target, the target shifts down after removal
   250→            if current_pos < target_pos {
   251→                target_pos - 1
   252→            } else {
   253→                target_pos
   254→            }
   255→        } else if let Some(ref after_str) = args.after {
   256→            let target = Coronet::jjrf_parse(after_str)
   257→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   258→            let target_key = target.jjrf_display();
   259→
   260→            if target_key == move_key {
   261→                return Err("Cannot position pace relative to itself".to_string());
   262→            }
   263→
   264→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   265→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   266→
   267→            // If moving from before target, the target shifts down after removal
   268→            if current_pos < target_pos {
   269→                target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   270→            } else {
   271→                target_pos + 1
   272→            }
   273→        } else {
   274→            unreachable!()
   275→        };
   276→
   277→        // Remove from current position and insert at new position
   278→        heat.order.remove(current_pos);
   279→        heat.order.insert(new_pos, move_key);
   280→
   281→    } else {
   282→        // Order mode has been removed
   283→        if !args.order.is_empty() {
   284→            return Err("Order mode removed. Use --move to reposition individual paces.".to_string());
   285→        }
   286→        return Err("No --move specified. Use --move CORONET with a positioning flag (--first, --last, --before, --after).".to_string());
   287→    }
   288→
   289→    // Return the new order
   290→    Ok(heat.order.clone())
   291→}
