   293→/// Tally - add a new Tack to a Pace
   294→///
   295→/// Prepends a new Tack with state transition and/or plan refinement.
   296→pub fn jjrg_tally(gallops: &mut jjrg_Gallops, args: jjrg_TallyArgs) -> Result<(), String> {
   297→    // Parse and normalize coronet
   298→    let coronet = Coronet::jjrf_parse(&args.coronet)
   299→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   300→    let coronet_key = coronet.jjrf_display();
   301→
   302→    // Extract parent Firemark
   303→    let firemark = coronet.jjrf_parent_firemark();
   304→    let firemark_key = firemark.jjrf_display();
   305→
   306→    // Verify Heat exists
   307→    let heat = gallops.heats.get_mut(&firemark_key)
   308→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   309→
   310→    // Verify Pace exists
   311→    let pace = heat.paces.get_mut(&coronet_key)
   312→        .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   313→
   314→    // Read current Tack
   315→    let current_tack = pace.tacks.first()
   316→        .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   317→
   318→    // Check for the new-spec-invalidates-bridled condition:
   319→    // If pace is currently bridled AND new spec text is provided AND no explicit --state,
   320→    // then auto-reset to rough (new spec invalidates old direction)
   321→    let auto_reset_to_rough = args.state.is_none()
   322→        && matches!(current_tack.state, jjrg_PaceState::Bridled)
   323→        && args.text.is_some();
   324→
   325→    // Determine new state
   326→    let new_state = if auto_reset_to_rough {
   327→        jjrg_PaceState::Rough
   328→    } else {
   329→        args.state.clone().unwrap_or_else(|| current_tack.state.clone())
   330→    };
   331→
   332→    // Determine new direction
   333→    let new_direction = match (&args.state, &new_state) {
   334→        // State explicitly set to bridled: direction required
   335→        (Some(jjrg_PaceState::Bridled), _) => {
   336→            match &args.direction {
   337→                Some(d) if !d.is_empty() => Some(d.clone()),
   338→                Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   339→                None => return Err("direction is required when state is bridled".to_string()),
   340→            }
   341→        }
   342→        // State explicitly set to something other than bridled: direction forbidden
   343→        (Some(_), _) => {
   344→            if args.direction.is_some() {
   345→                return Err("direction must be absent when state is not bridled".to_string());
   346→            }
   347→            None
   348→        }
   349→        // Auto-reset to rough: no direction
   350→        _ if auto_reset_to_rough => None,
   351→        // State inherited and was bridled: inherit direction
   352→        (None, jjrg_PaceState::Bridled) => {
   353→            args.direction.or_else(|| current_tack.direction.clone())
   354→        }
   355→        // State inherited and was not bridled: no direction
   356→        (None, _) => None,
   357→    };
   358→
   359→    // Determine new text
   360→    let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   361→    if new_text.is_empty() {
   362→        return Err("text must not be empty".to_string());
   363→    }
   364→
   365→    // Determine new silks
   366→    let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
   367→
   368→    // Create new Tack
   369→    let new_tack = jjrg_make_tack(
   370→        new_state,
   371→        new_text,
   372→        new_silks,
   373→        new_direction,
   374→    );
   375→
   376→    // Prepend to tacks array
   377→    pace.tacks.insert(0, new_tack);
   378→
   379→    Ok(())
   380→}
