   382→/// Draft - move a Pace from one Heat to another
   383→///
   384→/// Moves the pace to the destination heat with a new Coronet.
   385→/// All Tack history is preserved, with a new Tack recording the draft.
   386→/// State is NOT changed - draft is a move operation, not a state transition.
   387→pub fn jjrg_draft(gallops: &mut jjrg_Gallops, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
   388→    // Validate positioning mutual exclusivity
   389→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   390→        .iter()
   391→        .filter(|&&x| x)
   392→        .count();
   393→    if position_count > 1 {
   394→        return Err("Only one of --before, --after, or --first may be specified".to_string());
   395→    }
   396→
   397→    // Parse and normalize source coronet
   398→    let source_coronet = Coronet::jjrf_parse(&args.coronet)
   399→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   400→    let source_coronet_key = source_coronet.jjrf_display();
   401→
   402→    // Extract source Firemark from coronet
   403→    let source_firemark = source_coronet.jjrf_parent_firemark();
   404→    let source_firemark_key = source_firemark.jjrf_display();
   405→
   406→    // Parse and normalize destination firemark
   407→    let dest_firemark = Firemark::jjrf_parse(&args.to)
   408→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   409→    let dest_firemark_key = dest_firemark.jjrf_display();
   410→
   411→    // Validate source and destination are different
   412→    if source_firemark_key == dest_firemark_key {
   413→        return Err("Cannot draft pace to same heat".to_string());
   414→    }
   415→
   416→    // Verify source heat exists
   417→    if !gallops.heats.contains_key(&source_firemark_key) {
   418→        return Err(format!("Source heat '{}' not found", source_firemark_key));
   419→    }
   420→
   421→    // Verify destination heat exists
   422→    if !gallops.heats.contains_key(&dest_firemark_key) {
   423→        return Err(format!("Heat '{}' not found", dest_firemark_key));
   424→    }
   425→
   426→    // Verify pace exists in source heat
   427→    {
   428→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
   429→        if !source_heat.paces.contains_key(&source_coronet_key) {
   430→            return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
   431→        }
   432→    }
   433→
   434→    // Validate positioning target if specified
   435→    let insert_position = if let Some(ref before_str) = args.before {
   436→        let target = Coronet::jjrf_parse(before_str)
   437→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   438→        let target_key = target.jjrf_display();
   439→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   440→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   441→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   442→        Some(pos)
   443→    } else if let Some(ref after_str) = args.after {
   444→        let target = Coronet::jjrf_parse(after_str)
   445→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   446→        let target_key = target.jjrf_display();
   447→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   448→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   449→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   450→        Some(pos + 1)
   451→    } else if args.first {
   452→        Some(0)
   453→    } else {
   454→        None // Append to end
   455→    };
   456→
   457→    // Remove pace from source heat
   458→    let source_heat = gallops.heats.get_mut(&source_firemark_key).unwrap();
   459→    let pace_data = source_heat.paces.remove(&source_coronet_key)
   460→        .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
   461→    source_heat.order.retain(|c| c != &source_coronet_key);
   462→
   463→    // Get destination heat and allocate new coronet
   464→    let dest_heat = gallops.heats.get_mut(&dest_firemark_key).unwrap();
   465→    let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
   466→
   467→    // Create new tack recording the draft
   468→    let first_tack = pace_data.tacks.first();
   469→    let draft_note = format!("Drafted from {} in {}.\n\n{}",
   470→        source_coronet_key, source_firemark_key,
   471→        first_tack.map(|t| t.text.as_str()).unwrap_or(""));
   472→
   473→    let draft_tack = jjrg_make_tack(
   474→        first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
   475→        draft_note,
   476→        first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
   477→        first_tack.and_then(|t| t.direction.clone()),
   478→    );
   479→
   480→    // Build new pace with draft tack prepended
   481→    let mut new_tacks = vec![draft_tack];
   482→    new_tacks.extend(pace_data.tacks);
   483→
   484→    let new_pace = jjrg_Pace {
   485→        tacks: new_tacks,
   486→    };
   487→
   488→    // Insert into destination heat
   489→    match insert_position {
   490→        Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
   491→        None => dest_heat.order.push(new_coronet_str.clone()),
   492→    }
   493→    dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
   494→
   495→    // Increment destination seed
   496→    dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
   497→
   498→    Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
   499→}
