   501→/// Retire a Heat
   502→///
   503→/// Creates trophy file, removes heat from gallops, deletes paddock file.
   504→/// Does NOT save gallops or commit - caller is responsible for that.
   505→pub fn jjrg_retire(
   506→    gallops: &mut jjrg_Gallops,
   507→    args: jjrg_RetireArgs,
   508→    base_path: &Path,
   509→    steeplechase: &[SteeplechaseEntry],
   510→) -> Result<jjrg_RetireResult, String> {
   511→    // Parse and normalize firemark
   512→    let firemark = Firemark::jjrf_parse(&args.firemark)
   513→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   514→    let firemark_key = firemark.jjrf_display();
   515→
   516→    // Validate today is YYMMDD
   517→    if !zjjrg_is_yymmdd(&args.today) {
   518→        return Err(format!("today must be YYMMDD format, got '{}'", args.today));
   519→    }
   520→
   521→    // Verify heat exists
   522→    let heat = gallops.heats.get(&firemark_key)
   523→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   524→
   525→    // Read paddock content before we remove anything
   526→    let paddock_path = base_path.join(&heat.paddock_file);
   527→    let paddock_content = fs::read_to_string(&paddock_path)
   528→        .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
   529→
   530→    // Build trophy content
   531→    let trophy_content = zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
   532→
   533→    // Compute trophy path: .claude/jjm/retired/jjh_b<created>-r<today>-<silks>.md
   534→    let trophy_filename = format!(
   535→        "jjh_b{}-r{}-{}.md",
   536→        heat.creation_time,
   537→        args.today,
   538→        heat.silks
   539→    );
   540→    let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
   541→    let trophy_full_path = base_path.join(&trophy_rel_path);
   542→
   543→    // Create retired directory if needed
   544→    if let Some(parent) = trophy_full_path.parent() {
   545→        fs::create_dir_all(parent)
   546→            .map_err(|e| format!("Failed to create retired directory: {}", e))?;
   547→    }
   548→
   549→    // Write trophy file
   550→    fs::write(&trophy_full_path, trophy_content)
   551→        .map_err(|e| format!("Failed to write trophy file: {}", e))?;
   552→
   553→    // Capture info for result before removing heat
   554→    let silks = heat.silks.clone();
   555→    let paddock_file = heat.paddock_file.clone();
   556→
   557→    // Remove heat from gallops (do NOT change next_heat_seed)
   558→    // Use shift_remove to preserve order of remaining heats
   559→    gallops.heats.shift_remove(&firemark_key);
   560→
   561→    // Delete paddock file
   562→    if paddock_path.exists() {
   563→        fs::remove_file(&paddock_path)
   564→            .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
   565→    }
   566→
   567→    Ok(jjrg_RetireResult {
   568→        trophy_path: trophy_rel_path,
   569→        paddock_path: paddock_file,
   570→        silks,
   571→        firemark: firemark_key,
   572→    })
   573→}
   574→
   575→/// Build trophy markdown preview (dry-run, no file modifications)
   576→///
   577→/// Returns the markdown content that would be written to the trophy file.
   578→pub fn jjrg_build_trophy_preview(
   579→    gallops: &jjrg_Gallops,
   580→    firemark: &str,
   581→    paddock_content: &str,
   582→    today: &str,
   583→    steeplechase: &[SteeplechaseEntry],
   584→) -> Result<String, String> {
   585→    // Parse and normalize firemark
   586→    let fm = Firemark::jjrf_parse(firemark)
   587→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   588→    let firemark_key = fm.jjrf_display();
   589→
   590→    // Verify heat exists
   591→    let heat = gallops.heats.get(&firemark_key)
   592→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   593→
   594→    zjjrg_build_trophy_content(&firemark_key, heat, paddock_content, today, steeplechase)
   595→}
