   597→/// Build trophy markdown content
   598→fn zjjrg_build_trophy_content(
   599→    firemark_key: &str,
   600→    heat: &jjrg_Heat,
   601→    paddock_content: &str,
   602→    today: &str,
   603→    steeplechase: &[SteeplechaseEntry],
   604→) -> Result<String, String> {
   605→    let mut content = String::new();
   606→
   607→    // Header
   608→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
   609→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
   610→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
   611→    content.push_str(&format!("**Retired:** {}\n", today));
   612→    content.push_str("**Status:** retired\n\n");
   613→
   614→    // Paddock
   615→    content.push_str("## Paddock\n\n");
   616→    content.push_str(paddock_content);
   617→    if !paddock_content.ends_with('\n') {
   618→        content.push('\n');
   619→    }
   620→    content.push('\n');
   621→
   622→    // Paces (in order)
   623→    content.push_str("## Paces\n\n");
   624→    for coronet_key in &heat.order {
   625→        if let Some(pace) = heat.paces.get(coronet_key) {
   626→            // Get final state from most recent tack
   627→            let final_state = pace.tacks.first()
   628→                .map(|t| match t.state {
   629→                    jjrg_PaceState::Rough => "rough",
   630→                    jjrg_PaceState::Bridled => "bridled",
   631→                    jjrg_PaceState::Complete => "complete",
   632→                    jjrg_PaceState::Abandoned => "abandoned",
   633→                })
   634→                .unwrap_or("unknown");
   635→
   636→            let pace_silks = pace.tacks.first()
   637→                .map(|t| t.silks.as_str())
   638→                .unwrap_or("unknown");
   639→
   640→            content.push_str(&format!(
   641→                "### {} ({}) [{}]\n\n",
   642→                pace_silks, coronet_key, final_state
   643→            ));
   644→
   645→            // Tack history (newest first, as stored)
   646→            for tack in &pace.tacks {
   647→                let state_str = match tack.state {
   648→                    jjrg_PaceState::Rough => "rough",
   649→                    jjrg_PaceState::Bridled => "bridled",
   650→                    jjrg_PaceState::Complete => "complete",
   651→                    jjrg_PaceState::Abandoned => "abandoned",
   652→                };
   653→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
   654→                content.push_str(&tack.text);
   655→                if !tack.text.ends_with('\n') {
   656→                    content.push('\n');
   657→                }
   658→                if let Some(ref direction) = tack.direction {
   659→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
   660→                }
   661→                content.push('\n');
   662→            }
   663→        }
   664→    }
   665→
   666→    // Commit Activity (bitmap views)
   667→    let firemark = Firemark::jjrf_parse(firemark_key)
   668→        .map_err(|e| format!("Invalid firemark in trophy builder: {}", e))?;
   669→    content.push_str("## Commit Activity\n\n");
   670→    content.push_str("```\n");
   671→    if let Ok(bitmap) = jjrpd_format_file_bitmap(&firemark, heat) {
   672→        content.push_str(&bitmap);
   673→    }
   674→    if let Ok(swimlanes) = jjrpd_format_commit_swimlanes(&firemark, heat) {
   675→        content.push_str(&swimlanes);
   676→    }
   677→    content.push_str("```\n\n");
   678→
   679→    // Steeplechase (newest first, as provided)
   680→    content.push_str("## Steeplechase\n\n");
   681→    if steeplechase.is_empty() {
   682→        content.push_str("(no entries)\n\n");
   683→    } else {
   684→        for entry in steeplechase {
   685→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
   686→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
   687→            let action = entry.action.as_deref().unwrap_or("notch");
   688→            content.push_str(&format!(
   689→                "### {} - {} - {}\n\n",
   690→                entry.timestamp, identity, action
   691→            ));
   692→            content.push_str(&entry.subject);
   693→            if !entry.subject.ends_with('\n') {
   694→                content.push('\n');
   695→            }
   696→            content.push('\n');
   697→        }
   698→    }
   699→
   700→    Ok(content)
   701→}
