   703→/// Curry - update Heat paddock with chalk entry
   704→///
   705→/// Writes new paddock content and creates a chalk commit recording the change.
   706→pub fn jjrg_curry(
   707→    gallops_path: &std::path::Path,
   708→    firemark: &Firemark,
   709→    new_content: &str,
   710→    note: Option<&str>,
   711→) -> Result<(), String> {
   712→    use std::fs;
   713→
   714→    // Load gallops
   715→    let gallops = jjrg_Gallops::jjrg_load(gallops_path)
   716→        .map_err(|e| format!("Failed to load Gallops: {}", e))?;
   717→
   718→    // Verify heat exists
   719→    let firemark_key = firemark.jjrf_display();
   720→    let heat = gallops.heats.get(&firemark_key)
   721→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   722→
   723→    // Write new paddock content
   724→    let paddock_path = std::path::Path::new(&heat.paddock_file);
   725→    fs::write(paddock_path, new_content)
   726→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   727→
   728→    // Build chalk message
   729→    let description = if let Some(n) = note {
   730→        format!("paddock curried: {}", n)
   731→    } else {
   732→        "paddock curried".to_string()
   733→    };
   734→
   735→    // Create chalk commit using vvc
   736→    use crate::jjrn_notch::jjrn_format_heat_discussion;
   737→    let message = jjrn_format_heat_discussion(firemark, &description);
   738→
   739→    let commit_args = vvc::vvcm_CommitArgs {
   740→        files: vec![paddock_path.to_string_lossy().to_string()],
   741→        message,
   742→        size_limit: vvc::VVCG_SIZE_LIMIT,
   743→        warn_limit: vvc::VVCG_WARN_LIMIT,
   744→    };
   745→
   746→    // Acquire lock for commit
   747→    let lock = vvc::vvcc_CommitLock::vvcc_acquire()
   748→        .map_err(|e| format!("Failed to acquire commit lock: {}", e))?;
   749→
   750→    match vvc::machine_commit(&lock, &commit_args) {
   751→        Ok(hash) => {
   752→            eprintln!("jjx_curry: committed {}", &hash[..8]);
   753→            Ok(())
   754→        }
   755→        Err(e) => Err(format!("Commit failed: {}", e)),
   756→    }
   757→    // lock released here
   758→}
