   760→/// Furlough a Heat - change status or rename
   761→///
   762→/// Updates heat status (racing/stabled) and/or silks.
   763→/// At least one change must be requested.
   764→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   765→    // Validate at least one option provided
   766→    if !args.racing && !args.stabled && args.silks.is_none() {
   767→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   768→    }
   769→
   770→    // Validate racing/stabled mutual exclusivity
   771→    if args.racing && args.stabled {
   772→        return Err("Cannot specify both --racing and --stabled".to_string());
   773→    }
   774→
   775→    // Validate silks if provided
   776→    if let Some(ref silks) = args.silks {
   777→        if !zjjrg_is_kebab_case(silks) {
   778→            return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", silks));
   779→        }
   780→    }
   781→
   782→    // Parse and normalize firemark
   783→    let firemark = Firemark::jjrf_parse(&args.firemark)
   784→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   785→    let firemark_key = firemark.jjrf_display();
   786→
   787→    // Verify Heat exists and check status
   788→    {
   789→        let heat = gallops.heats.get(&firemark_key)
   790→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   791→
   792→        // Check not retired (terminal state)
   793→        if heat.status == jjrg_HeatStatus::Retired {
   794→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   795→        }
   796→
   797→        // Note: requesting the same status is allowed — it promotes the heat
   798→        // to the top of its list (racing or stabled) for reordering purposes.
   799→    }
   800→
   801→    // Apply status change if requested — also promotes heat to top of list
   802→    if args.racing {
   803→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
   804→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   805→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   806→        }
   807→    } else if args.stabled {
   808→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
   809→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   810→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   811→        }
   812→    }
   813→
   814→    // Apply silks change if requested
   815→    if let Some(silks) = args.silks {
   816→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
   817→    }
   818→
   819→    Ok(())
   820→}
   821→
   822→/// Garland a Heat - celebrate completion and create continuation
   823→///
   824→/// Updates source heat silks to garlanded form and status to stabled.
   825→/// Creates new heat with continuation silks, status racing.
   826→/// Transfers actionable paces (rough/bridled) to new heat.
   827→/// Retains complete/abandoned paces in garlanded heat.
   828→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
   829→    use crate::jjrc_core::jjrc_timestamp_from_env;
   830→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
   831→
   832→    // Parse and normalize firemark
   833→    let firemark = Firemark::jjrf_parse(&args.firemark)
   834→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   835→    let firemark_key = firemark.jjrf_display();
   836→
   837→    // Verify source heat exists and extract needed data (avoid holding the borrow)
   838→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
   839→        let source_heat = gallops.heats.get(&firemark_key)
   840→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   841→
   842→        // Parse source silks to determine sequence
   843→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
   844→        let seq = sequence.unwrap_or(1);
   845→
   846→        // Count actionable paces
   847→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
   848→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   849→                if let Some(tack) = pace.tacks.first() {
   850→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   851→                } else {
   852→                    false
   853→                }
   854→            } else {
   855→                false
   856→            }
   857→        }).count();
   858→
   859→        // Validate there are actionable paces to transfer
   860→        if actionable_count == 0 {
   861→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
   862→        }
   863→
   864→        // Count retained paces
   865→        let retained_count = source_heat.paces.len() - actionable_count;
   866→
   867→        // Count complete paces for steeplechase marker
   868→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
   869→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   870→                if let Some(tack) = pace.tacks.first() {
   871→                    tack.state == jjrg_PaceState::Complete
   872→                } else {
   873→                    false
   874→                }
   875→            } else {
   876→                false
   877→            }
   878→        }).count();
   879→
   880→        // Create steeplechase marker entry
   881→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
   882→
   883→        // Update source heat: add steeplechase marker (prepend to paddock file)
   884→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
   885→        let existing_content = std::fs::read_to_string(&source_paddock_path)
   886→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   887→
   888→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
   889→        std::fs::write(&source_paddock_path, updated_content)
   890→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   891→
   892→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
   893→    };
   894→
   895→    // Build garlanded and continuation silks
   896→    let (base, seq) = source_silks;
   897→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
   898→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
   899→
   900→    // Nominate new heat with continuation silks
   901→    let created_ts = jjrc_timestamp_from_env();
   902→    let nominate_args = jjrg_NominateArgs {
   903→        silks: continuation_silks.clone(),
   904→        created: created_ts,
   905→    };
   906→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
   907→    let new_firemark_key = nominate_result.firemark.clone();
   908→
   909→    // Get destination heat paddock file for copy
   910→    let dest_paddock_file = {
   911→        let dest_heat = gallops.heats.get(&new_firemark_key)
   912→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
   913→        dest_heat.paddock_file.clone()
   914→    };
   915→
   916→    // Read original paddock content before modifications (for new heat)
   917→    let source_paddock_path = base_path.join(&source_paddock_file);
   918→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
   919→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   920→
   921→    // Extract original content (removing marker we just added)
   922→    let existing_content = original_paddock_content.split_once("\n\n")
   923→        .map(|(_, rest)| rest)
   924→        .unwrap_or(&original_paddock_content);
   925→
   926→    // Copy paddock content from source to new heat
   927→    let dest_paddock_path = base_path.join(&dest_paddock_file);
   928→    std::fs::write(&dest_paddock_path, existing_content)
   929→        .map_err(|e| format!("Failed to copy paddock to new heat: {}", e))?;
   930→
   931→    // Draft all actionable paces to new heat (in order)
   932→    for coronet_key in source_order {
   933→        if let Some(pace) = gallops.heats.get(&firemark_key).unwrap().paces.get(&coronet_key) {
   934→            if let Some(tack) = pace.tacks.first() {
   935→                if matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled) {
   936→                    // Draft this pace to new heat (append to end)
   937→                    let draft_args = jjrg_DraftArgs {
   938→                        coronet: coronet_key.clone(),
   939→                        to: new_firemark_key.clone(),
   940→                        before: None,
   941→                        after: None,
   942→                        first: false, // Append to end to maintain order
   943→                    };
   944→                    jjrg_draft(gallops, draft_args)?;
   945→                }
   946→            }
   947→        }
   948→    }
   949→
   950→    // Update source heat: change silks to garlanded, set status to stabled
   951→    let source_heat_mut = gallops.heats.get_mut(&firemark_key).unwrap();
   952→    source_heat_mut.silks = garlanded_silks.clone();
   953→    source_heat_mut.status = jjrg_HeatStatus::Stabled;
   954→
   955→    // Set new heat status to racing and move to front
   956→    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
   957→    new_heat_mut.status = jjrg_HeatStatus::Racing;
   958→    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
   959→        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
   960→    }
   961→
   962→    Ok(jjrg_GarlandResult {
   963→        old_firemark: firemark_key,
   964→        old_silks: garlanded_silks,
   965→        new_firemark: new_firemark_key,
   966→        new_silks: continuation_silks,
   967→        paces_transferred: actionable_count,
   968→        paces_retained: retained_count,
   969→    })
   970→}
   971→
   972→/// Restring - bulk draft multiple paces atomically
   973→///
   974→/// Moves multiple paces from source heat to destination heat in a single operation.
   975→/// All paces are validated before any mutations occur.
   976→/// Order is preserved in the destination heat.
   977→pub fn jjrg_restring(gallops: &mut jjrg_Gallops, args: jjrg_RestringArgs) -> Result<jjrg_RestringResult, String> {
   978→    // Parse and normalize firemarks
   979→    let source_firemark = Firemark::jjrf_parse(&args.source_firemark)
   980→        .map_err(|e| format!("Invalid source firemark: {}", e))?;
   981→    let source_firemark_key = source_firemark.jjrf_display();
   982→
   983→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
   984→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   985→    let dest_firemark_key = dest_firemark.jjrf_display();
   986→
   987→    // Validate firemarks are different
   988→    if source_firemark_key == dest_firemark_key {
   989→        return Err("Cannot draft paces to same heat".to_string());
   990→    }
   991→
   992→    // Validate both heats exist
   993→    if !gallops.heats.contains_key(&source_firemark_key) {
   994→        return Err(format!("Heat '{}' not found", source_firemark_key));
   995→    }
   996→    if !gallops.heats.contains_key(&dest_firemark_key) {
   997→        return Err(format!("Heat '{}' not found", dest_firemark_key));
   998→    }
   999→
  1000→    // Validate coronet array is non-empty
  1001→    if args.coronets.is_empty() {
  1002→        return Err("No paces specified for draft".to_string());
  1003→    }
  1004→
  1005→    // Validate all coronets before any mutations
  1006→    let mut normalized_coronets = Vec::new();
  1007→    for coronet_str in &args.coronets {
  1008→        // Parse and normalize coronet
  1009→        let coronet = Coronet::jjrf_parse(coronet_str)
  1010→            .map_err(|e| format!("Invalid coronet '{}': {}", coronet_str, e))?;
  1011→        let coronet_key = coronet.jjrf_display();
  1012→
  1013→        // Verify coronet belongs to source heat
  1014→        let coronet_firemark = coronet.jjrf_parent_firemark();
  1015→        if coronet_firemark.jjrf_display() != source_firemark_key {
  1016→            return Err(format!(
  1017→                "Pace {} does not belong to source heat {}",
  1018→                coronet_key, source_firemark_key
  1019→            ));
  1020→        }
  1021→
  1022→        // Verify pace exists in source heat
  1023→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1024→        if !source_heat.paces.contains_key(&coronet_key) {
  1025→            return Err(format!(
  1026→                "Pace {} not found in heat {}",
  1027→                coronet_key, source_firemark_key
  1028→            ));
  1029→        }
  1030→
  1031→        normalized_coronets.push(coronet_key);
  1032→    }
  1033→
  1034→    // All validations passed - now perform the operations
  1035→
  1036→    // Capture source heat info before mutations
  1037→    let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1038→    let source_silks = source_heat.silks.clone();
  1039→    let source_paddock = source_heat.paddock_file.clone();
  1040→
  1041→    // Capture destination heat info
  1042→    let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
  1043→    let dest_silks = dest_heat.silks.clone();
  1044→    let dest_paddock = dest_heat.paddock_file.clone();
  1045→
  1046→    // Draft each pace to destination (preserving order)
  1047→    let mut mappings = Vec::new();
  1048→    for coronet_key in normalized_coronets {
  1049→        let draft_args = jjrg_DraftArgs {
  1050→            coronet: coronet_key.clone(),
  1051→            to: dest_firemark_key.clone(),
  1052→            before: None,
  1053→            after: None,
  1054→            first: false, // Append to end to preserve order
  1055→        };
  1056→
  1057→        // Get pace info before drafting (for output)
  1058→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1059→        let pace = source_heat.paces.get(&coronet_key).unwrap();
  1060→        let first_tack = pace.tacks.first();
  1061→        let silks = first_tack.map(|t| t.silks.clone()).unwrap_or_default();
  1062→        let state = first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough);
  1063→        let spec_full = first_tack.map(|t| t.text.clone()).unwrap_or_default();
  1064→        let spec_preview = if spec_full.len() > 80 {
  1065→            format!("{}...", &spec_full[..77])
  1066→        } else {
  1067→            spec_full.clone()
  1068→        };
  1069→
  1070→        // Perform the draft
