   100→/// Get all steeplechase entries for a heat with file touch data per commit.
   101→///
   102→/// Returns entries plus a mapping of coronet -> set of bare work filenames.
   103→/// Also returns heat-level (no coronet) work files separately.
   104→/// Used by the file-touch bitmap visualization.
   105→pub fn jjrq_file_touches_for_heat(firemark_raw: &str) -> Result<jjrq_HeatFileTouches, String> {
   106→    let rein_args = jjrs_ReinArgs {
   107→        firemark: firemark_raw.to_string(),
   108→        limit: 10000,
   109→    };
   110→
   111→    let entries = jjrs_get_entries(&rein_args)?;
   112→
   113→    let mut pace_files: std::collections::BTreeMap<String, std::collections::BTreeSet<String>> = std::collections::BTreeMap::new();
   114→    let mut heat_files: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
   115→    let mut coronets_seen: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
   116→
   117→    for entry in &entries {
   118→        let commit_files: Vec<String> = zjjrq_files_for_commit(&entry.commit)
   119→            .into_iter()
   120→            .filter(|p| !zjjrq_is_infra_file(p))
   121→            .map(|p| zjjrq_bare_filename(&p))
   122→            .collect();
   123→
   124→        if let Some(ref coronet) = entry.coronet {
   125→            coronets_seen.insert(coronet.clone());
   126→            let set = pace_files.entry(coronet.clone()).or_default();
   127→            for f in commit_files {
   128→                set.insert(f);
   129→            }
   130→        } else {
   131→            for f in commit_files {
   132→                heat_files.insert(f);
   133→            }
   134→        }
   135→    }
   136→
   137→    Ok(jjrq_HeatFileTouches {
   138→        pace_files,
   139→        heat_files,
   140→        coronets_with_commits: coronets_seen,
   141→    })
   142→}
