   221→/// Build garlanded silks: "garlanded-{base}-{seq:02}"
   222→pub fn jjrq_build_garlanded_silks(base: &str, seq: u32) -> String {
   223→    format!("garlanded-{}-{:02}", base, seq)
   224→}
   225→
   226→/// Build continuation silks: "{base}-{seq:02}"
   227→pub fn jjrq_build_continuation_silks(base: &str, seq: u32) -> String {
   228→    format!("{}-{:02}", base, seq)
   229→}
